// Berechne Vormonat
const now = new Date();
const year = now.getMonth() === 0 ? now.getFullYear() - 1 : now.getFullYear();
const month = now.getMonth() === 0 ? 12 : now.getMonth();
const monthStr = String(month).padStart(2, '0');
const lastDay = new Date(year, month, 0).getDate();

const accounts = [
  { id: 'act_1538907656986107', name: 'Razeco UG' },
  { id: 'act_1162322016047465', name: 'Deniz Akin' }
];

const output = [];
for (const acc of accounts) {
  output.push({
    json: {
      account_id: acc.id,
      account_name: acc.name,
      since: `${year}-${monthStr}-01`,
      until: `${year}-${monthStr}-${lastDay}`,
      monat: `${year}-${monthStr}`
    }
  });
}

return output;

const items = $input.all();
const monat = items[0]?.json?.monat || 'unknown';
const account = items[0]?.json?.account_name || 'unknown';

const rows = [];
for (const item of items) {
  const d = item.json.data || [item.json];
  for (const row of (Array.isArray(d) ? d : [d])) {
    if (!row.campaign_id) continue;
    const conversions = (row.actions || []).find(a => a.action_type === 'offsite_conversion.fb_pixel_purchase' || a.action_type === 'purchase');
    const costPerConv = (row.cost_per_action_type || []).find(a => a.action_type === 'offsite_conversion.fb_pixel_purchase' || a.action_type === 'purchase');
    const revenue = (row.action_values || []).find(a => a.action_type === 'offsite_conversion.fb_pixel_purchase' || a.action_type === 'purchase');
    const spend = parseFloat(row.spend || 0);
    const rev = parseFloat(revenue?.value || 0);
    rows.push({
      json: {
        values: [[
          monat,
          account,
          row.campaign_id,
          row.campaign_name,
          row.status || '',
          spend,
          parseInt(row.impressions || 0),
          parseInt(row.reach || 0),
          parseFloat(row.frequency || 0),
          parseInt(row.clicks || 0),
          parseFloat(row.ctr || 0),
          parseFloat(row.cpm || 0),
          parseInt(conversions?.value || 0),
          parseFloat(costPerConv?.value || 0),
          spend > 0 ? (rev / spend).toFixed(2) : 0
        ]]
      }
    });
  }
}
return rows;

